using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a REST API via HttpClient.
/// HttpClient is injected through the constructor by the DI container.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Retrieve a list of users from the API.")]
    public async Task<string> ListUsers(
        [Description("Maximum number of results to return (1-100).")] int limit = 10,
        CancellationToken cancellationToken = default)
    {
        var response = await httpClient.GetAsync($"/users?limit={limit}", cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }

    [McpServerTool, Description("Get a single user by their unique identifier.")]
    public async Task<string> GetUser(
        [Description("The unique ID of the user to retrieve.")] int userId,
        CancellationToken cancellationToken = default)
    {
        var response = await httpClient.GetAsync($"/users/{userId}", cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }

    [McpServerTool(Destructive = false, ReadOnly = false),
     Description("Create a new user with the given name and email address.")]
    public async Task<string> CreateUser(
        [Description("Full name of the new user.")] string name,
        [Description("Email address for the new user.")] string email,
        CancellationToken cancellationToken = default)
    {
        var payload = JsonSerializer.Serialize(new { name, email }, JsonOptions);
        var content = new StringContent(payload, System.Text.Encoding.UTF8, "application/json");

        var response = await httpClient.PostAsync("/users", content, cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }
}

